import * as React from "react";
import { useEffect, useState } from "react";
import PropTypes from "prop-types";
import { Helmet } from "react-helmet";

import { Layout } from "../components";
// import { MetaData } from "../components/meta";
import data from "../data/blog.json";

/**
 * Single post view (/:slug)
 *
 * Fetches content based on the provided slug from the JSON data.
 */
const Post = ({ location, pageContext }) => {
    const { slug } = pageContext;
    const postEdge = data.allGhostPost.edges.find((edge) => edge.node.slug === slug);
    const post = postEdge ? postEdge.node : null;

    const [content, setContent] = useState("");

    useEffect(() => {
        if (post && post.html) {
            fetch(post.html) // 讀取 .txt 檔案
                .then((res) => res.text()) // 解析為純文字
                .then((data) => setContent(data)) // 設定內容
                .catch((err) => console.error("Failed to load content:", err));
        }
    }, [post]);

    if (!post) {
        return (
            <Layout>
                <div className="container">
                    <h1>Post not found</h1>
                    <p>Sorry, the post you are looking for does not exist.</p>
                </div>
            </Layout>
        );
    }

    return (
        <>
            {/* <MetaData location={location} title={post.meta_title} description={post.meta_description} type="article" /> */}
            <Helmet>
                <style type="text/css">{post.codeinjection_styles || ""}</style>
            </Helmet>
            <Layout>
                <div className="container">
                    <article className="content">
                        {/* {post.feature_image && (
                            <figure className="post-feature-image">
                                <img src={post.feature_image} alt={post.title} />
                            </figure>
                        )} */}
                        <section className="post-full-content">
                            <h1 className="content-title">{post.title}</h1>
                            <section
                                className="content-body load-external-scripts"
                                dangerouslySetInnerHTML={{ __html: content }}
                            />
                        </section>
                    </article>
                </div>
            </Layout>
        </>
    );
};

Post.propTypes = {
    location: PropTypes.object.isRequired,
};

export default Post;